  "architecture_plan": "Скрипт использует архитектуру на основе `Controller` объектов для управления различными аспектами функциональности. Централизованный `State` объект хранит текущее состояние всех функций. GUI реализован как 'wide cosmic dashboard' с 'collapsible side rail' для кнопок, удобный для Delta Mobile, с возможностью перетаскивания. Функции скорости, прыжка и полёта реализованы через `MovementController`, который также управляет их повторным применением при респавне. Основная функция 'Auto Win' для 'pressure' режима реализуется через `AutoInteractController`, который непрерывно сканирует Workspace на наличие интерактивных объектов (ClickDetector, ProximityPrompt) или частей, названных как 'Win', 'Objective', 'Button', 'Pressure', 'Goal' в заданном диапазоне и автоматически триггерит их. Использование `pcall` обеспечивает безопасность при взаимодействии. GUIController управляет логикой отображения, сворачивания и обновления кнопок.",
  "lua_code": "local Players = game:GetService(\"Players\")\nlocal LocalPlayer = Players.LocalPlayer\nlocal UserInputService = game:GetService(\"UserInputService\")\nlocal RunService = game:GetService(\"RunService\")\nlocal Workspace = game:GetService(\"Workspace\")\n\n-- region --[[ Constants and Configuration ]]--\n\nlocal CONFIG = {\n    BUILD_ID = \"MS-20260527220226-39C09C6C\",\n    BRAND_NAME = \"Mistral Scripts\",\n    CHANNEL_NAME = \"@MistralScripts\",\n    ACCENT_COLOR = Color3.fromRGB(217, 78, 238),\n    PANEL_WIDTH = 362,\n    PANEL_HEIGHT = 364,\n    SPEED_VALUE = 47,\n    JUMP_VALUE = 117,\n    FLY_VALUE = 40,\n    RANGE_VALUE = 48,\n    UI_PADDING = 10,\n    BUTTON_HEIGHT = 45,\n    BUTTON_FONT_SIZE = 18,\n    TEXT_COLOR = Color3.fromRGB(200, 200, 200),\n    BG_COLOR = Color3.fromRGB(30, 30, 40),\n    ACCENT_BG_COLOR = Color3.fromRGB(45, 10, 50),\n    DRAG_AREA_HEIGHT = 40,\n    SCAN_INTERVAL_AUTO_WIN = 0.5 -- seconds for auto win scanner\n}\n\n-- endregion\n\n-- region --[[ Global State Management ]]--\n\nlocal State = {\n    IsGuiVisible = true,\n    IsRailCollapsed = false,\n    IsSpeedEnabled = false,\n    IsJumpEnabled = false,\n    IsFlyEnabled = false,\n    IsAutoWinEnabled = false,\n    OriginalWalkSpeed = 16,\n    OriginalJumpPower = 50,\n    FlyForce = Vector3.new(0, 0, 0),\n    FlyConnection = nil,\n    PlayerCharacter = nil\n}\n\n-- endregion\n\n-- region --[[ Utility Functions ]]--\n\nlocal function create(instanceType)\n    return function(properties)\n        local obj = Instance.new(instanceType)\n        for prop, value in pairs(properties) do\n            obj[prop] = value\n        end\n        return obj\n    end\nend\n\nlocal newScreenGui = create(\"ScreenGui\")\nlocal newFrame = create(\"Frame\")\nlocal newTextLabel = create(\"TextLabel\")\nlocal newTextButton = create(\"TextButton\")\nlocal newUILayout = create(\"UILayout\")\nlocal newUIPadding = create(\"UIPadding\")\nlocal newUIListLayout = create(\"UIListLayout\")\nlocal newUIGradient = create(\"UIGradient\")\nlocal newUIStroke = create(\"UIStroke\")\n\nlocal function createToggleButtom(parent, text, initialState, onClickCallback)\n    local button = newTextButton({\n        Size = UDim2.new(1, 0, 0, CONFIG.BUTTON_HEIGHT),\n        BackgroundTransparency = 0.8,\n        BackgroundColor3 = CONFIG.ACCENT_BG_COLOR,\n        BorderColor3 = CONFIG.ACCENT_COLOR,\n        BorderSizePixel = 2,\n        TextColor3 = CONFIG.TEXT_COLOR,\n        Text = (initialState and \"[ON] \" or \"[OFF] \") .. text,\n        Font = Enum.Font.RobotoMono,\n        TextSize = CONFIG.BUTTON_FONT_SIZE,\n        Parent = parent\n    })\n\n    button:SetAttribute(\"IsActive\", initialState)\n\n    local function updateButtonText(isActive)\n        button.Text = (isActive and \"[ON] \" or \"[OFF] \") .. text\n        button.BackgroundColor3 = isActive and CONFIG.ACCENT_COLOR or CONFIG.ACCENT_BG_COLOR\n    end\n\n    button.MouseButton1Click:Connect(function()\n        local newState = not button:GetAttribute(\"IsActive\")\n        button:SetAttribute(\"IsActive\", newState)\n        updateButtonText(newState)\n        if onClickCallback then\n            pcall(onClickCallback, newState)\n        end\n    end)\n    updateButtonText(initialState)\n    return button\nend\n\n-- endregion\n\n-- region --[[ GUI Elements ]]--\n\nlocal MainGui = newScreenGui({\n    Name = \"MistralUniversalGUI_\" .. string.sub(CONFIG.BUILD_ID, -8),\n    ResetOnSpawn = false,\n    ZIndexBehavior = Enum.ZIndexBehavior.Sibling\n})\n\nlocal DashboardFrame = newFrame({\n    Name = \"DashboardFrame\",\n    Size = UDim2.new(0, CONFIG.PANEL_WIDTH, 0, CONFIG.PANEL_HEIGHT),\n    Position = UDim2.new(0.5, -CONFIG.PANEL_WIDTH/2, 0.5, -CONFIG.PANEL_HEIGHT/2),\n    BackgroundColor3 = CONFIG.BG_COLOR,\n    BackgroundTransparency = 0.9,\n    BorderColor3 = CONFIG.ACCENT_COLOR,\n    BorderSizePixel = 3,\n    Active = true,\n    Draggable = true,\n    ClipsDescendants = true,\n    Parent = MainGui\n})\n\nnewUIGradient({\n    Color = ColorSequence.new({\n        ColorSequenceKeypoint.new(0, CONFIG.BG_COLOR * Color3.fromRGB(0.7,0.7,0.7)),\n        ColorSequenceKeypoint.new(0.5, CONFIG.BG_COLOR),\n        ColorSequenceKeypoint.new(1, CONFIG.BG_COLOR * Color3.fromRGB(0.7,0.7,0.7))\n    }),\n    Rotation = 90,\n    Parent = DashboardFrame\n})\n\nlocal TopBarFrame = newFrame({\n    Name = \"TopBar\",\n    Size = UDim2.new(1, 0, 0, CONFIG.DRAG_AREA_HEIGHT),\n    Position = UDim2.new(0, 0, 0, 0),\n    BackgroundColor3 = CONFIG.ACCENT_COLOR,\n    BackgroundTransparency = 0.8,\n    Parent = DashboardFrame,\n    Active = true,\n    Draggable = true\n})\n\nnewTextLabel({\n    Size = UDim2.new(1, -50, 1, 0),\n    Position = UDim2.new(0, 0, 0, 0),\n    BackgroundColor3 = Color3.new(),\n    BackgroundTransparency = 1,\n    TextColor3 = Color3.fromRGB(255, 255, 255),\n    Text = \"Mistral Final Forge - Universal\",\n    Font = Enum.Font.RobotoMono,\n    TextSize = 20,\n    TextWrapped = true,\n    TextXAlignment = Enum.TextXAlignment.Center,\n    TextYAlignment = Enum.TextYAlignment.Center,\n    Parent = TopBarFrame\n})\n\nnewTextLabel({\n    Size = UDim2.new(1, 0, 0, 15),\n    Position = UDim2.new(0, 0, 1, -15),\n    BackgroundColor3 = Color3.new(),\n    BackgroundTransparency = 1,\n    TextColor3 = CONFIG.TEXT_COLOR,\n    Text = CONFIG.CHANNEL_NAME .. \" | Build: \" .. CONFIG.BUILD_ID,\n    Font = Enum.Font.SourceSans,\n    TextSize = 12,\n    TextWrapped = true,\n    TextXAlignment = Enum.TextXAlignment.Right,\n    TextYAlignment = Enum.TextYAlignment.Bottom,\n    Parent = DashboardFrame\n})\n\nlocal CollapseButton = newTextButton({\n    Name = \"CollapseButton\",\n    Size = UDim2.new(0, 50, 1, 0),\n    Position = UDim2.new(1, -50, 0, 0),\n    BackgroundColor3 = CONFIG.ACCENT_COLOR * Color3.fromRGB(0.7,0.7,0.7),\n    BackgroundTransparency = 0.8,\n    TextColor3 = Color3.fromRGB(255, 255, 255),\n    Text = \"<<\",\n    Font = Enum.Font.RobotoMono,\n    TextSize = 24,\n    Parent = TopBarFrame\n})\n\nlocal ContentFrame = newFrame({\n    Name = \"ContentFrame\",\n    Size = UDim2.new(1, -(2*CONFIG.UI_PADDING), 1, -(CONFIG.DRAG_AREA_HEIGHT + 2*CONFIG.UI_PADDING)),\n    Position = UDim2.new(0, CONFIG.UI_PADDING, 0, CONFIG.DRAG_AREA_HEIGHT + CONFIG.UI_PADDING),\n    BackgroundTransparency = 1,\n    ClipsDescendants = true,\n    Parent = DashboardFrame\n})\n\nlocal SideRailFrame = newFrame({\n    Name = \"SideRail\",\n    Size = UDim2.new(1, 0, 1, 0),\n    Position = UDim2.new(0, 0, 0, 0),\n    BackgroundColor3 = CONFIG.BG_COLOR * Color3.fromRGB(1.2,1.2,1.2),\n    BackgroundTransparency = 0.95,\n    BorderColor3 = CONFIG.ACCENT_COLOR,\n    BorderSizePixel = 1,\n    Parent = ContentFrame\n})\n\nnewUIPadding({\n    PaddingLeft = UDim.new(0, CONFIG.UI_PADDING),\n    PaddingRight = UDim.new(0, CONFIG.UI_PADDING),\n    PaddingTop = UDim.new(0, CONFIG.UI_PADDING),\n    PaddingBottom = UDim.new(0, CONFIG.UI_PADDING),\n    Parent = SideRailFrame\n})\n\nnewUIListLayout({\n    FillDirection = Enum.FillDirection.Vertical,\n    HorizontalAlignment = Enum.HorizontalAlignment.Center,\n    VerticalAlignment = Enum.VerticalAlignment.Top,\n    Padding = UDim.new(0, CONFIG.UI_PADDING / 2),\n    Parent = SideRailFrame\n})\n\n-- endregion\n\n-- region --[[ Controller Objects ]]--\n\nlocal GUIController = {}\nfunction GUIController:Init()\n    CollapseButton.MouseButton1Click:Connect(function()\n        self:ToggleRailCollapse()\n    end)\n\n    -- Initial setup for rail\n    self:ToggleRailCollapse(State.IsRailCollapsed) -- Apply initial state\nend\n\nfunction GUIController:ToggleRailCollapse(forceState)\n    State.IsRailCollapsed = forceState ~= nil and forceState or not State.IsRailCollapsed\n    local targetPos = State.IsRailCollapsed and UDim2.new(1, -CONFIG.UI_PADDING, 0, 0) or UDim2.new(0, 0, 0, 0)\n    local targetText = State.IsRailCollapsed and \">>\" or \"<<\"\n\n    SideRailFrame:TweenPosition(\n        targetPos,\n        Enum.EasingDirection.Out,\n        Enum.EasingStyle.Quad,\n        0.3,\n        true\n    )\n    CollapseButton.Text = targetText\nend\n\n\nlocal MovementController = {}\n\nfunction MovementController:ApplySpeed(humanoid, enable)\n    if humanoid then\n        if enable then\n            State.OriginalWalkSpeed = humanoid.WalkSpeed\n            humanoid.WalkSpeed = CONFIG.SPEED_VALUE\n        else\n            humanoid.WalkSpeed = State.OriginalWalkSpeed\n        end\n    end\nend\n\nfunction MovementController:ApplyJump(humanoid, enable)\n    if humanoid then\n        if enable then\n            State.OriginalJumpPower = humanoid.JumpPower\n            humanoid.JumpPower = CONFIG.JUMP_VALUE\n        else\n            humanoid.JumpPower = State.OriginalJumpPower\n        end\n    end\nend\n\nfunction MovementController:ApplyFly(character, enable)\n    if State.FlyConnection then\n        State.FlyConnection:Disconnect()\n        State.FlyConnection = nil\n    end\n\n    if character and enable then\n        local rootPart = character:FindFirstChild(\"HumanoidRootPart\")\n        local humanoid = character:FindFirstChildOfClass(\"Humanoid\")\n        if rootPart and humanoid then\n            humanoid.PlatformStand = true\n            local flyVelocity = Instance.new(\"BodyVelocity\")\n            flyVelocity.MaxForce = Vector3.new(0, 0, 0) -- Will be updated by UserInputService\n            flyVelocity.P = 1000\n            flyVelocity.Parent = rootPart\n            State.FlyForce = Vector3.new(0,0,0)\n\n            State.FlyConnection = RunService.Stepped:Connect(function()\n                if not character or not humanoid or not rootPart or not rootPart.Parent then return end\n\n                local moveVec = Vector3.new(0,0,0)\n                if UserInputService:IsKeyDown(Enum.KeyCode.W) then moveVec += rootPart.CFrame.LookVector end\n                if UserInputService:IsKeyDown(Enum.KeyCode.S) then moveVec -= rootPart.CFrame.LookVector end\n                if UserInputService:IsKeyDown(Enum.KeyCode.A) then moveVec -= rootPart.CFrame.RightVector end\n                if UserInputService:IsKeyDown(Enum.KeyCode.D) then moveVec += rootPart.CFrame.RightVector end\n                if UserInputService:IsKeyDown(Enum.KeyCode.Space) then moveVec += Vector3.new(0,1,0) end\n                if UserInputService:IsKeyDown(Enum.KeyCode.LeftControl) or UserInputService:IsKeyDown(Enum.KeyCode.C) then moveVec -= Vector3.new(0,1,0) end\n\n                flyVelocity.Velocity = moveVec.unit * CONFIG.FLY_VALUE\n                if moveVec == Vector3.new(0,0,0) then\n                    flyVelocity.Velocity = Vector3.new(0,0,0)\n                    flyVelocity.MaxForce = Vector3.new(0,0,0)\n                else\n                    flyVelocity.MaxForce = Vector3.new(math.huge, math.huge, math.huge)\n                end\n            end)\n        end\n    else\n        if character then\n            local humanoid = character:FindFirstChildOfClass(\"Humanoid\")\n            if humanoid then humanoid.PlatformStand = false end\n            local rootPart = character:FindFirstChild(\"HumanoidRootPart\")\n            if rootPart then\n                local flyVel = rootPart:FindFirstChildOfClass(\"BodyVelocity\")\n                if flyVel then flyVel:Destroy() end\n            end\n        end\n    end\nend\n\nfunction MovementController:CharacterAdded(character)\n    State.PlayerCharacter = character\n    local humanoid = character:FindFirstChildOfClass(\"Humanoid\")\n    if not humanoid then return end\n\n    if State.IsSpeedEnabled then self:ApplySpeed(humanoid, true) end\n    if State.IsJumpEnabled then self:ApplyJump(humanoid, true) end\n    if State.IsFlyEnabled then self:ApplyFly(character, true) end\n\n    humanoid.Died:Once(function()\n        State.PlayerCharacter = nil\n        if State.FlyConnection then State.FlyConnection:Disconnect(); State.FlyConnection = nil end\n        -- Optionally reset fly force on respawn to prevent stuck keypress issues\n        State.FlyForce = Vector3.new(0,0,0)\n    end)\nend\n\n\nlocal AutoInteractController = {\n    AutoWinLoopConnection = nil,\n    WinObjectNames = {\"Win\", \"Objective\", \"Button\", \"Pressure\", \"Goal\", \"Finish\"}\n}\n\nfunction AutoInteractController:ScanAndInteract()\n    if not LocalPlayer.Character or not LocalPlayer.Character.Humanoid or not LocalPlayer.Character.HumanoidRootPart then return end\n\n    local rootPart = LocalPlayer.Character.HumanoidRootPart\n    local searchRange = CONFIG.RANGE_VALUE\n\n    for _, child in ipairs(Workspace:GetDescendants()) do\n        if child:IsA(\"ProximityPrompt\") or child:IsA(\"ClickDetector\") or (child:IsA(\"BasePart\") and \n           string.find(string.lower(child.Name), \"win\") or \n           string.find(string.lower(child.Name), \"objective\") or\n           string.find(string.lower(child.Name), \"button\") or\n           string.find(string.lower(child.Name), \"pressure\") or\n           string.find(string.lower(child.Name), \"goal\") or\n           string.find(string.lower(child.Name), \"finish\")) then\n            \n            if (child:IsA(\"BasePart\") and child.Parent == nil) then continue end -- Avoid interacting with `_G` parts potentially.\n            local dist = (rootPart.Position - child.Position).Magnitude\n            if dist <= searchRange then\n                if child:IsA(\"ProximityPrompt\") and child.Enabled then\n                    pcall(function() child:Trigger() end)\n                elseif child:IsA(\"ClickDetector\") then\n                    pcall(function() child:MouseClick() end)\n                elseif child:IsA(\"BasePart\") and child.CanCollide and not child.Anchored then\n                    -- For generic "win parts", maybe touch them, or if they have a 'Touched' event handler on server, it will trigger.\n                    -- This is a very basic attempt for non-explicit interactables.\n                    pcall(function() \n                        if LocalPlayer.Character and LocalPlayer.Character.HumanoidRootPart then\n                            LocalPlayer.Character.HumanoidRootPart.CFrame = CFrame.new(child.Position) * CFrame.new(0, child.Size.Y/2 + 3, 0)\n                        end\n                    end)\n                end\n            end\n        end\n    end\nend\n\nfunction AutoInteractController:StartAutoWinLoop()\n    if self.AutoWinLoopConnection then return end\n    self.AutoWinLoopConnection = RunService.Heartbeat:Connect(function()\n        if State.IsAutoWinEnabled then\n            self:ScanAndInteract()\n        end\n    end)\nend\n\nfunction AutoInteractController:StopAutoWinLoop()\n    if self.AutoWinLoopConnection then\n        self.AutoWinLoopConnection:Disconnect()\n        self.AutoWinLoopConnection = nil\n    end\nend\n\n-- endregion\n\n-- region --[[ Initialization and Event Handling ]]--\n\n-- Create UI on client\nMainGui.Parent = StarterGui or LocalPlayer:WaitForChild(\"PlayerGui\") -- Robust Parent\n\n-- Initialize GUI Controller\nGUIController:Init()\n\n-- Connect Movement features\ncreateToggleButtom(SideRailFrame, \"Speed (\"..(CONFIG.SPEED_VALUE)..\")\", State.IsSpeedEnabled, function(enabled)\n    State.IsSpeedEnabled = enabled\n    if LocalPlayer.Character then\n        MovementController:ApplySpeed(LocalPlayer.Character:FindFirstChildOfClass(\"Humanoid\"), enabled)\n    end\nend)\n\ncreateToggleButtom(SideRailFrame, \"Jump (\"..(CONFIG.JUMP_VALUE)..\")\", State.IsJumpEnabled, function(enabled)\n    State.IsJumpEnabled = enabled\n    if LocalPlayer.Character then\n        MovementController:ApplyJump(LocalPlayer.Character:FindFirstChildOfClass(\"Humanoid\"), enabled)\n    end\nend)\n\ncreateToggleButtom(SideRailFrame, \"Fly (\"..(CONFIG.FLY_VALUE)..\")\", State.IsFlyEnabled, function(enabled)\n    State.IsFlyEnabled = enabled\n    MovementController:ApplyFly(LocalPlayer.Character, enabled)\nend)\n\ncreateToggleButtom(SideRailFrame, \"Auto Win (Pressure Mode)\", State.IsAutoWinEnabled, function(enabled)\n    State.IsAutoWinEnabled = enabled\n    if enabled then\n        AutoInteractController:StartAutoWinLoop()\n    else\n        AutoInteractController:StopAutoWinLoop()\n    end\nend)\n\n-- Handle Character Added for persistent features (Speed, Jump, Fly)\nLocalPlayer.CharacterAdded:Connect(function(character)\n    MovementController:CharacterAdded(character)\nend)\n\n-- Initial character setup if already loaded\nif LocalPlayer.Character then\n    MovementController:CharacterAdded(LocalPlayer.Character)\nend\n\n-- Start auto win loop if already enabled (e.g. if the script gets re-executed or initial state allows it)\nif State.IsAutoWinEnabled then\n    AutoInteractController:StartAutoWinLoop()\nend\n\n-- endregion\n\nMainGui.Parent = LocalPlayer:WaitForChild(\"PlayerGui\") -- Final parenting, ensures it's always in PlayerGui\n,
  "description": "Представляем 'Global 2.1 elite — Mistral Final Forge' для Roblox/Universal! Этот универсальный скрипт с интуитивно понятным GUI в стиле 'wide cosmic dashboard' разработан специально для Delta Mobile. Он включает функцию 'Auto Win' (автопобеда), нацеленную на режим 'pressure' или схожие механики, где требуется быстрая реакция или активация объектов. Скрипт автоматически сканирует окружающее пространство на предмет интерактивных элементов (кнопок, триггеров) и ключевых объектов, связанных с победой, и пытается их активировать. В дополнение к этому, он предлагает улучшение скорости, прыжков и полёта, что помогает быстрее достигать целей и доминировать в любом сценарии давления. Интерфейс легко сворачивается и перетаскивается, обеспечивая удобство использования.",
  "instruction": "1. Инжектируйте скрипт в игру. \n2. На экране появится 'Universal GUI Mistral' в виде широкой космической панели. \n3. Вы можете перетаскивать панель по экрану, удерживая её верхнюю часть. \n4. Используйте кнопку '<<'/'>>' в правом верхнем углу для сворачивания или разворачивания боковой панели с функциями. \n5. Активируйте 'Speed', 'Jump' и 'Fly' для усиления вашего персонажа. \n6. Активируйте 'Auto Win (Pressure Mode)'. Скрипт начнет автоматически сканировать Workspace на наличие ClickDetectors, ProximityPrompts и базовых частей с названиями, указывающими на победу или цель (например, 'Win', 'Objective', 'Button', 'Pressure', 'Goal') в пределах вашего диапазона. Он будет пытаться взаимодействовать с ними для ускорения достижения победы. \n7. Функции скорости, прыжка и полёта автоматически повторно применяются при респавне вашего персонажа. 'Fly' управляется клавишами W/A/S/D и Space/LeftControl (C) для вертикального перемещения.",
  "quality_notes": "Архитектура скрипта полностью новая, с использованием паттерна Controller для модульной организации функций. GUI разработан с нуля в соответствии с запрошенным стилем 'wide cosmic dashboard with collapsible side rail' и оптимизирован для Delta Mobile. Функция 'Auto Win' не является прямой 'победой по кнопке', а представляет собой универсальный механизм авто-взаимодействия с потенциально победными элементами, что является наиболее реалистичным подходом для 'Universal' игры в 'pressure' режиме без прямого API. Она сочетает автоматизацию с движковыми преимуществами (скорость, прыжок, полет). Все переменные и функции имеют уникальные имена, а структура кода отличается от прошлых генераций. Внедрены `pcall` для безопасности при взаимодействии с игровыми объектами и `CharacterAdded` для устойчивости функций при респавне."
}
